CREATE DATABASE IF NOT EXISTS trinetra;
USE trinetra;

CREATE TABLE IF NOT EXISTS USERS (
  ID INT AUTO_INCREMENT PRIMARY KEY,
  NAME VARCHAR(100) NOT NULL,
  EMAIL VARCHAR(150) NOT NULL UNIQUE,
  MOBILE VARCHAR(15) NOT NULL UNIQUE,
  PASSWORD_HASH VARCHAR(255) NOT NULL,
  ID_TYPE VARCHAR(30) NOT NULL,
  USER_ID VARCHAR(100) NOT NULL UNIQUE,
  HALL_TICKET VARCHAR(50) NOT NULL UNIQUE,
  CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS EXAMS (
  ID INT AUTO_INCREMENT PRIMARY KEY,
  SLUG VARCHAR(50) NOT NULL UNIQUE,
  TITLE VARCHAR(120) NOT NULL,
  DESCRIPTION TEXT,
  DURATION_MINUTES INT NOT NULL DEFAULT 10,
  TOTAL_QUESTIONS INT NOT NULL DEFAULT 10,
  IS_ACTIVE BOOLEAN NOT NULL DEFAULT TRUE,
  CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS QUESTIONS (
  ID INT AUTO_INCREMENT PRIMARY KEY,
  EXAM_ID INT NOT NULL,
  QUESTION_TEXT TEXT NOT NULL,
  OPTION_A VARCHAR(500) NOT NULL,
  OPTION_B VARCHAR(500) NOT NULL,
  OPTION_C VARCHAR(500) NOT NULL,
  OPTION_D VARCHAR(500) NOT NULL,
  CORRECT_OPTION ENUM('a','b','c','d') NOT NULL,
  CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (EXAM_ID) REFERENCES EXAMS(ID) ON DELETE CASCADE
);

CREATE TABLE IF NOT EXISTS USER_EXAM_QUESTIONS (
  ID INT AUTO_INCREMENT PRIMARY KEY,
  USER_ID INT NOT NULL,
  EXAM_ID INT NOT NULL,
  QUESTION_ID INT NOT NULL,
  DISPLAY_ORDER INT NOT NULL,
  CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  UNIQUE KEY UNIQUE_USER_EXAM_QUESTION (USER_ID, EXAM_ID, QUESTION_ID),
  FOREIGN KEY (USER_ID) REFERENCES USERS(ID) ON DELETE CASCADE,
  FOREIGN KEY (EXAM_ID) REFERENCES EXAMS(ID) ON DELETE CASCADE,
  FOREIGN KEY (QUESTION_ID) REFERENCES QUESTIONS(ID) ON DELETE CASCADE
);

CREATE TABLE IF NOT EXISTS USER_ANSWERS (
  ID INT AUTO_INCREMENT PRIMARY KEY,
  USER_ID INT NOT NULL,
  EXAM_ID INT NOT NULL,
  QUESTION_ID INT NOT NULL,
  SELECTED_OPTION ENUM('a','b','c','d') NULL,
  IS_CORRECT BOOLEAN NOT NULL DEFAULT FALSE,
  CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  UNIQUE KEY UNIQUE_USER_ANSWER (USER_ID, EXAM_ID, QUESTION_ID),
  FOREIGN KEY (USER_ID) REFERENCES USERS(ID) ON DELETE CASCADE,
  FOREIGN KEY (EXAM_ID) REFERENCES EXAMS(ID) ON DELETE CASCADE,
  FOREIGN KEY (QUESTION_ID) REFERENCES QUESTIONS(ID) ON DELETE CASCADE
);

CREATE TABLE IF NOT EXISTS RESULTS (
  ID INT AUTO_INCREMENT PRIMARY KEY,
  USER_ID INT NOT NULL,
  EXAM_ID INT NOT NULL,
  TOTAL_QUESTIONS INT NOT NULL,
  CORRECT_ANSWERS INT NOT NULL,
  SCORE INT NOT NULL,
  PERCENTAGE INT NOT NULL,
  PASSED BOOLEAN NOT NULL DEFAULT FALSE,
  SUBMITTED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  UNIQUE KEY UNIQUE_USER_EXAM_RESULT (USER_ID, EXAM_ID),
  FOREIGN KEY (USER_ID) REFERENCES USERS(ID) ON DELETE CASCADE,
  FOREIGN KEY (EXAM_ID) REFERENCES EXAMS(ID) ON DELETE CASCADE
);


